import React, { useState, useRef } from 'react';
import { classifyWaste, IMPACT } from '../services/api';
import { addRecord, isDuplicate, claimDailyBonus, ECO_POINTS } from '../services/store';
import ResultCard from '../components/ResultCard';
import ImpactPanel from '../components/ImpactPanel';
import './Home.css';

export default function Home() {
  const [preview, setPreview]   = useState(null);
  const [file, setFile]         = useState(null);
  const [loading, setLoading]   = useState(false);
  const [result, setResult]     = useState(null);
  const [error, setError]       = useState('');
  const [toast, setToast]       = useState(null);
  const inputRef = useRef();

  function showToast(msg, type = 'success') {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  }

  function handleFileChange(e) {
    const f = e.target.files[0];
    if (!f) return;
    if (!f.type.startsWith('image/')) { showToast('Please select an image file', 'error'); return; }
    setFile(f);
    setResult(null);
    setError('');
    const reader = new FileReader();
    reader.onload = ev => setPreview(ev.target.result);
    reader.readAsDataURL(f);
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!file) { showToast('Select or capture an image first', 'error'); return; }
    const duplicate = isDuplicate(file);
    setLoading(true); setError(''); setResult(null);
    try {
      const data = await classifyWaste(file);
      const category  = data.prediction;
      const impact    = IMPACT[category];
      if (!impact) throw new Error('Unknown category: ' + category);

      // If duplicate, still show the classification but don't award points or store a record.
      const earned = duplicate ? 0 : (ECO_POINTS[category] || 5);
      const gotBonus = duplicate ? false : claimDailyBonus();
      const totalPts = earned + (gotBonus ? ECO_POINTS.DailyBonus : 0);
      const record = duplicate ? null : addRecord(category, impact.guidance, file);

      setResult({
        category,
        impact: {
          ...impact,
          detectedObject: data.object || data.detectedObject || null,
          confidence: data.confidence != null ? Number(data.confidence) : null,
        },
        record,
        ecoPoints: earned,
        bonusPoints: gotBonus ? ECO_POINTS.DailyBonus : 0,
      });

      if (duplicate) {
        showToast('Duplicate image detected — classified, but no eco-points earned.', 'error');
      } else {
        showToast('+' + totalPts + ' eco-points earned! 🌱');
      }
    } catch (err) {
      setError(err.message || 'Something went wrong. Is the server running?');
      showToast(err.message || 'Error', 'error');
    } finally { setLoading(false); }
  }

  function handleReset() {
    setPreview(null); setFile(null); setResult(null); setError('');
    if (inputRef.current) inputRef.current.value = '';
  }

  return (
    <div className="page-content home-page">

      {/* ── Dark Hero Header ── */}
      <header className="home-hero">
        <div className="hero-inner">
          <div className="hero-brand">
            <div className="brand-dot" />
            <span className="brand-name">VERDANT</span>
            <span className="brand-badge">AI</span>
          </div>
          <p className="hero-tagline">Waste Intelligence Platform</p>

          {!preview && (
            <>
              <h1 className="hero-heading">Identify &amp; Dispose<br />Waste Correctly</h1>
              <p className="hero-sub">Point your camera at any waste item for instant AI classification and eco-guidance.</p>
            </>
          )}
        </div>

        {/* Decorative background circles */}
        <div className="hero-circle hero-circle-1" />
        <div className="hero-circle hero-circle-2" />
      </header>

      {/* ── Scan / Upload Section ── */}
      <section className="scan-section">
        {!preview ? (
          <div className="scan-idle">
            {/* Viewfinder UI */}
            <div className="viewfinder">
              <div className="vf-corner vf-tl" /><div className="vf-corner vf-tr" />
              <div className="vf-corner vf-bl" /><div className="vf-corner vf-br" />
              <div className="vf-scan-line" />
              <div className="vf-center">
                <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="rgba(0,200,150,.7)" strokeWidth="1.5">
                  <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/>
                  <circle cx="12" cy="13" r="4"/>
                </svg>
                <p className="vf-label">Frame your waste item here</p>
              </div>
            </div>

            <div className="scan-actions">
              <label className="action-btn action-primary" htmlFor="camera-input">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/>
                  <circle cx="12" cy="13" r="4"/>
                </svg>
                Open Camera
              </label>
              <input id="camera-input" type="file" accept="image/*" capture="environment" hidden ref={inputRef} onChange={handleFileChange} />

              <label className="action-btn action-secondary" htmlFor="gallery-input">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/>
                  <polyline points="21 15 16 10 5 21"/>
                </svg>
                Upload Image
              </label>
              <input id="gallery-input" type="file" accept="image/*" hidden onChange={handleFileChange} />
            </div>

            <div className="scan-hint">
              <span className="hint-dot" />
              <span>Supports JPG · PNG · WEBP · up to 10 MB</span>
            </div>
          </div>
        ) : (
          <div className="preview-section">
            <div className="preview-wrap">
              <img src={preview} alt="Waste item" className="preview-img" />
              <button className="preview-clear" onClick={handleReset}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
              </button>
              {loading && (
                <div className="preview-scanning">
                  <div className="scan-beam" />
                  <p className="scanning-text">Analysing…</p>
                </div>
              )}
            </div>
            {!result && !loading && (
              <form onSubmit={handleSubmit}>
                <button type="submit" className="action-btn action-primary action-full">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                    <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
                  </svg>
                  Classify This Item
                </button>
              </form>
            )}
          </div>
        )}
      </section>

      {/* ── Error ── */}
      {error && <div className="error-strip"><span>⚠ {error}</span></div>}

      {/* ── Results ── */}
      {result && (
        <div style={{ animation: 'fadeUp .4s ease both' }}>
          <ResultCard category={result.category} impact={result.impact} ecoPoints={result.ecoPoints} bonusPoints={result.bonusPoints} />
          <ImpactPanel impact={result.impact} single />
          <div className="rescan-row">
            <button className="action-btn action-ghost" onClick={handleReset}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-3.5"/>
              </svg>
              Scan Another Item
            </button>
          </div>
        </div>
      )}

      {/* ── How It Works ── */}
      {!preview && !result && (
        <section className="how-section">
          <div className="section-label">HOW IT WORKS</div>
          <div className="how-steps">
            {[
              { n: '01', title: 'Capture', desc: 'Use camera or upload any waste image.' },
              { n: '02', title: 'AI Analyse', desc: 'Our model classifies in under 1 second.' },
              { n: '03', title: 'Act Right', desc: 'Get bin guidance & your eco impact score.' },
            ].map(s => (
              <div className="how-step" key={s.n}>
                <span className="step-num">{s.n}</span>
                <div className="step-body">
                  <p className="step-title">{s.title}</p>
                  <p className="step-desc">{s.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {toast && <div className={`toast ${toast.type}`}>{toast.msg}</div>}
    </div>
  );
}
